const items = $input.all();

function generateId() {
  const timestamp = Date.now().toString(36).toUpperCase().padStart(10, '0');
  const random = Array.from({ length: 16 }, () => Math.floor(Math.random() * 36).toString(36).toUpperCase()).join('');
  return timestamp + random;
}

return items.map(item => {
  const json = item.json || {};
  const body = (json.body && typeof json.body === 'object') ? json.body : json;
  const receivedAt = new Date().toISOString();
  const intakeId = (typeof body.intake_id === 'string' && body.intake_id.trim())
    ? body.intake_id.trim()
    : generateId();

  return {
    json: {
      intake_id: intakeId,
      received_at: receivedAt,
      raw_payload: body,
      synthetic: true
    }
  };
});

const items = $input.all();

const CONFIG = {
  operating_mode: 'VALIDATION',
  dry_run: true,
  live_campaigns: [],
  geo_code: 'US_B2B_CORE_12',
  validation_cells: [
    'CELL_1_SAAS_SALES_HIRING',
    'CELL_2_SAAS_EXISTING_OUTBOUND',
    'CELL_3_SPECIALISED_B2B_AGENCY'
  ],
  allowed_country: 'US',
  region_priority: ['EASTERN', 'CENTRAL'],
  transmission_disabled: true,
  external_actions_mocked: true
};

function detectLiveCampaignClaim(rawPayload) {
  const reasons = [];
  const campaignId = rawPayload && typeof rawPayload.campaign_id === 'string' ? rawPayload.campaign_id : null;

  if (campaignId && CONFIG.live_campaigns.includes(campaignId)) {
    reasons.push('campaign_id "' + campaignId + '" is present in LIVE_CAMPAIGNS');
  }
  if (rawPayload && rawPayload.dry_run === false) {
    reasons.push('raw_payload.dry_run is explicitly false');
  }
  if (rawPayload && typeof rawPayload.operating_mode === 'string' && rawPayload.operating_mode !== 'VALIDATION') {
    reasons.push('raw_payload.operating_mode is "' + rawPayload.operating_mode + '", not VALIDATION');
  }
  if (rawPayload && rawPayload.live_campaign === true) {
    reasons.push('raw_payload.live_campaign is explicitly true');
  }
  return reasons;
}

return items.map(item => {
  const input = item.json || {};
  const rawPayload = (input.raw_payload && typeof input.raw_payload === 'object') ? input.raw_payload : {};

  const liveCampaignReasons = detectLiveCampaignClaim(rawPayload);
  const dryRunOk = CONFIG.dry_run === true;
  const passed = dryRunOk && liveCampaignReasons.length === 0;

  const reasons = [];
  if (!dryRunOk) {
    reasons.push('CONFIG.dry_run is not true');
  }
  reasons.push(...liveCampaignReasons);

  const result = {
    ...input,
    config: CONFIG,
    config_gate: {
      passed,
      dry_run_ok: dryRunOk,
      live_campaign_claim_detected: liveCampaignReasons.length > 0,
      reasons
    }
  };

  if (!passed) {
    result.terminal_status = 'REJECTED';
    result.processing_halted = true;
  }

  return { json: result };
});

const items = $input.all();

const REQUIRED_FIELDS = [
  { nesPath: 'event_id', rawKeys: ['event_id'] },
  { nesPath: 'email_id', rawKeys: ['email_id'] },
  { nesPath: 'event_type', rawKeys: ['event_type'] },
  { nesPath: 'lead_email', rawKeys: ['lead_email'] },
  { nesPath: 'from_address_email', rawKeys: ['from_address_email'] },
  { nesPath: 'email_account', rawKeys: ['email_account'] },
  { nesPath: 'reply_subject', rawKeys: ['reply_subject'] },
  { nesPath: 'reply_text', rawKeys: ['reply_text'] },
  { nesPath: 'timestamp', rawKeys: ['timestamp'] },
  { nesPath: 'campaign_id', rawKeys: ['campaign_id'] },
  { nesPath: 'validation_cell', rawKeys: ['validation_cell'] }
];

return items.map(item => {
  const input = item.json || {};
  const rawPayload = input.raw_payload;

  const isMalformed = (
    rawPayload === null ||
    typeof rawPayload !== 'object' ||
    Array.isArray(rawPayload) ||
    typeof rawPayload.event_type !== 'string' ||
    rawPayload.event_type.trim() === ''
  );

  const validated = {};
  const validationErrors = [];

  if (isMalformed) {
    for (const field of REQUIRED_FIELDS) {
      validated[field.nesPath] = null;
    }
    validationErrors.push({
      field: 'event_type',
      issue: 'MISSING_OR_INVALID',
      detail: 'raw_payload is missing a non-empty string event_type; cannot determine event type.'
    });
  } else {
    for (const field of REQUIRED_FIELDS) {
      const raw = rawPayload[field.rawKeys[0]];
      if (raw === undefined || raw === null || (typeof raw === 'string' && raw.trim() === '')) {
        validated[field.nesPath] = null;
        validationErrors.push({ field: field.nesPath, issue: 'MISSING', detail: `raw_payload.${field.rawKeys[0]} is missing or empty.` });
      } else {
        validated[field.nesPath] = raw;
      }
    }
  }

  return {
    json: {
      ...input,
      validated,
      validation_errors: validationErrors,
      payload_status: isMalformed ? 'MALFORMED' : (validationErrors.length > 0 ? 'INCOMPLETE' : 'COMPLETE')
    }
  };
});

const items = $input.all();

const CELL_DEFINITIONS = {
  CELL_1_SAAS_SALES_HIRING: {
    segment: 'B2B SaaS',
    subsegment: '10-50 employees, recently hiring sales roles',
    pain_trigger: 'We hired sales capacity but pipeline is not keeping up',
    offer_angle: 'Capacity-aligned qualified meetings',
    geo_code: 'US_B2B_CORE_12'
  },
  CELL_2_SAAS_EXISTING_OUTBOUND: {
    segment: 'B2B SaaS',
    subsegment: 'Already using outbound tools/agencies/SDRs',
    pain_trigger: 'Outbound is producing volume, but quality is inconsistent',
    offer_angle: 'Fewer junk meetings, capacity-based targeting',
    geo_code: 'US_B2B_CORE_12'
  },
  CELL_3_SPECIALISED_B2B_AGENCY: {
    segment: 'B2B agencies',
    subsegment: '$5k+ monthly retainer services',
    pain_trigger: 'Founder-led sales depends too much on referrals and inconsistent pipeline',
    offer_angle: 'Predictable qualified meetings without hiring SDRs',
    geo_code: 'US_B2B_CORE_12'
  }
};

function emptyValidationLearning() {
  return {
    pain_confirmed: 'unknown',
    current_outbound_spend_confirmed: 'unknown',
    capacity_problem_confirmed: 'unknown',
    proof_objection: 'unknown',
    pricing_interest: 'unknown',
    alpha_interest: 'unknown',
    decision_maker_confirmed: 'unknown',
    discovery_call_booked: 'unknown',
    discovery_call_showed: 'unknown',
    validation_signal_strength: 'unknown',
    voice_of_customer_excerpt: null
  };
}

function detectAttachments(text, html) {
  const safeText = typeof text === 'string' ? text : '';
  const safeHtml = typeof html === 'string' ? html : '';
  const cidPattern = /<img[^>]+src="cid:/i;
  const wordPattern = /\b(see attached|please find attached|attached (?:is|are|please|the|for)|attachment\b)/i;
  return cidPattern.test(safeHtml) || wordPattern.test(safeHtml) || wordPattern.test(safeText);
}

function detectLanguage(text) {
  return (typeof text === 'string' && text.trim().length > 0) ? 'en' : 'unknown';
}

function normalizeSubject(subject) {
  let s = (typeof subject === 'string') ? subject.trim().toLowerCase() : '';
  let prevLength;
  do {
    prevLength = s.length;
    s = s.replace(/^(re|fwd|fw)\s*:\s*/i, '');
    s = s.trim();
  } while (s.length !== prevLength);
  return s.replace(/\s+/g, ' ');
}

function timeBucket(isoString) {
  const ms = Date.parse(isoString);
  if (isNaN(ms)) return 0;
  return Math.floor(ms / 1000 / 300);
}

function vendorPayloadHash(rawPayload) {
  const json = JSON.stringify(rawPayload === undefined ? null : rawPayload);
  let hash = 5381;
  for (let i = 0; i < json.length; i++) {
    hash = ((hash << 5) + hash) + json.charCodeAt(i);
    hash = hash & 0xFFFFFFFF;
  }
  const hex = (hash >>> 0).toString(16).padStart(8, '0');
  return 'phase3-placeholder-djb2:' + hex;
}

return items.map(item => {
  const input = item.json || {};
  const validated = input.validated || {};
  const rawPayload = (input.raw_payload && typeof input.raw_payload === 'object') ? input.raw_payload : {};

  const validationCellKey = (typeof validated.validation_cell === 'string' && CELL_DEFINITIONS[validated.validation_cell])
    ? validated.validation_cell
    : null;

  const campaignContext = validationCellKey
    ? {
        validation_cell: validationCellKey,
        segment: CELL_DEFINITIONS[validationCellKey].segment,
        subsegment: CELL_DEFINITIONS[validationCellKey].subsegment,
        pain_trigger: CELL_DEFINITIONS[validationCellKey].pain_trigger,
        offer_angle: CELL_DEFINITIONS[validationCellKey].offer_angle,
        geo_code: CELL_DEFINITIONS[validationCellKey].geo_code,
        campaign_purpose: 'UNKNOWN',
        campaign_message_variant: 'UNKNOWN'
      }
    : {
        validation_cell: 'UNKNOWN',
        segment: 'UNKNOWN',
        subsegment: 'UNKNOWN',
        pain_trigger: 'UNKNOWN',
        offer_angle: 'UNKNOWN',
        geo_code: 'UNKNOWN',
        campaign_purpose: 'UNKNOWN',
        campaign_message_variant: 'UNKNOWN'
      };

  const leadEmail = (typeof validated.lead_email === 'string') ? validated.lead_email.trim().toLowerCase() : null;
  const replyText = (typeof validated.reply_text === 'string') ? validated.reply_text : null;
  const replyHtml = (typeof rawPayload.reply_html === 'string') ? rawPayload.reply_html : null;
  const replySnippet = (typeof rawPayload.reply_text_snippet === 'string') ? rawPayload.reply_text_snippet : null;

  const hasAttachments = detectAttachments(replyText, replyHtml);
  const language = detectLanguage(replyText);

  const subjectNorm = normalizeSubject(validated.reply_subject);
  const bucket = timeBucket(input.received_at);
  const dedupeKey = 'instantly:' + (validated.campaign_id || 'UNKNOWN') + ':' + (leadEmail || 'unknown') + ':' + subjectNorm + ':' + bucket;

  const emailId = (typeof validated.email_id === 'string' && validated.email_id.trim()) ? validated.email_id.trim() : null;

  const nes = {
    nes_version: '1',
    intake_id: input.intake_id,
    received_at: input.received_at,
    source: 'instantly',
    event_type: validated.event_type || 'UNKNOWN',
    workspace_id: (typeof rawPayload.workspace === 'string') ? rawPayload.workspace : 'UNKNOWN',
    campaign_id: validated.campaign_id || 'UNKNOWN',
    campaign_name: (typeof rawPayload.campaign_name === 'string') ? rawPayload.campaign_name : 'UNKNOWN',
    campaign_context: campaignContext,
    lead_email: leadEmail || 'UNKNOWN',
    eaccount: validated.email_account || 'UNKNOWN',
    step: (typeof rawPayload.step === 'number') ? rawPayload.step : null,
    variant: (typeof rawPayload.variant === 'number') ? rawPayload.variant : null,
    is_first_reply: (typeof rawPayload.is_first === 'boolean') ? rawPayload.is_first : null,
    reply: {
      subject: validated.reply_subject || null,
      snippet: replySnippet,
      text: replyText,
      html: replyHtml,
      has_attachments: hasAttachments,
      language: language,
      from_address_email: (typeof validated.from_address_email === 'string' && validated.from_address_email.trim())
        ? validated.from_address_email.trim()
        : (leadEmail || null)
    },
    threading: {
      reply_to_uuid: emailId,
      thread_id: (typeof rawPayload.thread_id === 'string') ? rawPayload.thread_id : null,
      rfc_message_id_inbound: (typeof rawPayload.message_id === 'string') ? rawPayload.message_id : null,
      lookup_strategy: emailId ? 'from_payload' : 'lookup_by_lead_and_campaign'
    },
    links: {
      unibox_url: (typeof rawPayload.unibox_url === 'string') ? rawPayload.unibox_url : null
    },
    vendor_payload_hash: vendorPayloadHash(rawPayload),
    dedupe_key: dedupeKey,
    synthetic: input.synthetic === true,
    operating_mode: (input.config && input.config.operating_mode) ? input.config.operating_mode : 'VALIDATION',
    validation_learning_seed: emptyValidationLearning(),
    timestamps: {
      webhook_received_at: input.received_at || null,
      auth_completed_at: null,
      normalized_at: new Date().toISOString(),
      classification_started_at: null,
      classification_completed_at: null,
      draft_completed_at: null,
      human_notified_at: null,
      approved_at: null,
      send_attempted_at: null,
      transmission_verified_at: null,
      terminal_suppressed_at: null,
      terminal_no_reply_at: null,
      final_failure_at: null
    },
    policy_version: 'policy-HMZ-1.2',
    kb_version: 'KB-1.0-DRAFT',
    schema_version: 'nes-1'
  };

  return {
    json: {
      ...input,
      nes
    }
  };
});

const items = $input.all();

const STATE_ENUM = [
  'RECEIVED',
  'VALIDATING',
  'NORMALIZED',
  'DUPLICATE',
  'REJECTED',
  'READY_FOR_DECISION',
  'REVIEW_HOLD',
  'COMPLETED_NO_SEND',
  'FAILED'
];

function canonicalPayloadHash(value) {
  function canonicalize(v) {
    if (Array.isArray(v)) return v.map(canonicalize);
    if (v !== null && typeof v === 'object') {
      const out = {};
      for (const k of Object.keys(v).sort()) out[k] = canonicalize(v[k]);
      return out;
    }
    return v;
  }
  const json = JSON.stringify(canonicalize(value === undefined ? null : value));
  let hash = 5381;
  for (let i = 0; i < json.length; i++) {
    hash = ((hash << 5) + hash) + json.charCodeAt(i);
    hash = hash & 0xFFFFFFFF;
  }
  return (hash >>> 0).toString(16).padStart(8, '0');
}

return items.map(item => {
  const input = item.json || {};
  const validated = input.validated || {};
  const nes = input.nes || {};
  const rawPayload = input.raw_payload;

  const eventId = (typeof validated.event_id === 'string' && validated.event_id.trim()) ? validated.event_id.trim() : null;
  const emailId = (typeof validated.email_id === 'string' && validated.email_id.trim()) ? validated.email_id.trim() : null;
  const campaignId = (typeof validated.campaign_id === 'string' && validated.campaign_id.trim()) ? validated.campaign_id.trim() : null;
  const emailAccount = (typeof validated.email_account === 'string' && validated.email_account.trim()) ? validated.email_account.trim() : null;
  const leadEmail = (typeof nes.lead_email === 'string' && nes.lead_email.trim() && nes.lead_email !== 'UNKNOWN') ? nes.lead_email.trim() : null;

  const keyComponents = {
    event_id: eventId,
    email_id: emailId,
    campaign_id: campaignId,
    email_account: emailAccount,
    lead_email: leadEmail
  };
  const isIdentifierPoor = Object.values(keyComponents).some(v => v === null);

  let idempotencyKey;
  let keyScheme;

  if (!isIdentifierPoor) {
    idempotencyKey = [eventId, emailId, campaignId, emailAccount, leadEmail].join(':');
    keyScheme = 'full_identity';
  } else {
    const presentParts = Object.entries(keyComponents)
      .filter(([, v]) => v !== null)
      .map(([k, v]) => `${k}=${v}`);
    const payloadHash = canonicalPayloadHash(rawPayload);
    idempotencyKey = ['identifier_poor', 'instantly', ...presentParts, `payload_hash=${payloadHash}`].join(':');
    keyScheme = 'identifier_poor_hash';
  }

  const proposedState = (input.payload_status === 'MALFORMED') ? 'REJECTED' : 'READY_FOR_DECISION';

  return {
    json: {
      ...input,
      idempotency: {
        idempotency_key: idempotencyKey,
        key_scheme: keyScheme,
        key_components: keyComponents,
        proposed_state: proposedState,
        state_enum: STATE_ENUM,
        storage_adapter: 'n8n_data_table',
        storage_table_name: 'hmz_validation_reply_intake_idempotency'
      }
    }
  };
});

const items = $input.all();
const upstream = $('E1. Compute Idempotency Key').all();

return items.map((item, index) => {
  const row = item.json || {};
  const original = (upstream[index] && upstream[index].json) ? upstream[index].json : {};

  const createdAt = row.createdAt || row.created_at || null;
  const updatedAt = row.updatedAt || row.updated_at || null;
  const isDuplicate = !!(createdAt && updatedAt && createdAt !== updatedAt);

  return {
    json: {
      ...original,
      idempotency: {
        ...original.idempotency,
        is_duplicate: isDuplicate,
        table_row_id: (row.id !== undefined) ? row.id : null,
        created_at: createdAt,
        updated_at: updatedAt,
        duplicate_detection_method: 'created_at_vs_updated_at_after_upsert',
        duplicate_detection_status: 'VERIFIED_N8N_2_25_7'
      }
    }
  };
});

const items = $input.all();

const AUTOMATED_RESPONSE_PATTERN = /\b(auto[- ]?reply|automatic reply|automated response|do not reply)\b/i;
const OOO_PATTERN = /\b(out of (the )?office|ooo|on leave|on vacation|away from (the )?office|annual leave)\b/i;
const BOUNCE_PATTERN = /\b(undeliverable|delivery (status notification|failure)|mail delivery failed|bounce|returned mail|message not delivered|delivery has failed)\b/i;
const UNSUBSCRIBE_PATTERN = /\b(unsubscribe|opt[- ]?out|remove me from|stop (sending|emailing)|do not contact|take me off)\b/i;

const SUPPORTED_EVENT_TYPES = ['reply_received', 'auto_reply_received', 'email_bounced', 'lead_unsubscribed'];

return items.map(item => {
  const input = item.json || {};
  const nes = input.nes || {};
  const reply = nes.reply || {};

  const subject = typeof reply.subject === 'string' ? reply.subject : '';
  const text = typeof reply.text === 'string' ? reply.text : '';
  const snippet = typeof reply.snippet === 'string' ? reply.snippet : '';
  const haystack = (subject + ' ' + text + ' ' + snippet).toLowerCase();

  const isMalformedPayload = input.payload_status === 'MALFORMED';
  const isUnsupportedEventType = !SUPPORTED_EVENT_TYPES.includes(nes.event_type);
  const isDuplicateEvent = !!(input.idempotency && input.idempotency.is_duplicate === true);

  const leadEmail = typeof nes.lead_email === 'string' ? nes.lead_email.toLowerCase() : '';
  const eaccount = typeof nes.eaccount === 'string' ? nes.eaccount.trim().toLowerCase() : '';
  const isSelfSent = !!(leadEmail && eaccount && leadEmail !== 'unknown' && eaccount !== 'unknown' && leadEmail === eaccount);

  const isEmptyReply = text.trim() === '' && snippet.trim() === '';

  const isAutomatedResponse = nes.event_type === 'auto_reply_received' || AUTOMATED_RESPONSE_PATTERN.test(haystack);
  const isOutOfOffice = OOO_PATTERN.test(haystack);
  const isBounce = nes.event_type === 'email_bounced' || BOUNCE_PATTERN.test(haystack);
  const isUnsubscribeLanguage = nes.event_type === 'lead_unsubscribed' || UNSUBSCRIBE_PATTERN.test(haystack);

  const hasAttachments = reply.has_attachments === true;

  const campaignCellMismatch = !nes.campaign_context || nes.campaign_context.validation_cell === 'UNKNOWN';

  return {
    json: {
      ...input,
      prefilter: {
        is_unsupported_event_type: isUnsupportedEventType,
        is_malformed_payload: isMalformedPayload,
        is_duplicate_event: isDuplicateEvent,
        is_self_sent: isSelfSent,
        is_empty_reply: isEmptyReply,
        is_automated_response: isAutomatedResponse,
        is_out_of_office: isOutOfOffice,
        is_bounce: isBounce,
        is_unsubscribe_language: isUnsubscribeLanguage,
        has_attachments: hasAttachments,
        campaign_cell_mismatch: campaignCellMismatch
      }
    }
  };
});

const items = $input.all();

return items.map(item => {
  const input = item.json || {};
  const gate = input.config_gate || {};
  const reasons = Array.isArray(gate.reasons) ? gate.reasons : [];
  const reasonText = reasons.length > 0
    ? `Configuration gate failed: ${reasons.join('; ')}`
    : 'Configuration gate failed (no reasons recorded)';

  return {
    json: {
      ...input,
      terminal_status: 'REJECTED',
      processing_halted: true,
      external_action_status: 'NOOP',
      reason: reasonText
    }
  };
});

const items = $input.all();

return items.map(item => {
  const input = item.json || {};
  const key = (input.idempotency && input.idempotency.idempotency_key) ? input.idempotency.idempotency_key : 'UNKNOWN';

  return {
    json: {
      ...input,
      terminal_status: 'COMPLETED_NO_SEND',
      processing_halted: true,
      external_action_status: 'NOOP',
      stop_active_sequence: false,
      reason: `Duplicate event detected for idempotency key "${key}" (idempotency.is_duplicate=true); no further processing or send required.`
    }
  };
});

const items = $input.all();

// Fixed launch profile allowlists (policy-HMZ-1.2). Mirrors
// config/business-ready.config.json allowlists.*; all empty by
// default, which fails this gate closed for PRODUCTION_WEBHOOK
// entries until the owner configures them and the apply step
// re-embeds the configured values.
// HMZ_INJECT_BEGIN:ALLOWLISTS
const ALLOWLISTS = {"workspace_id":"c7f84f11-4a1a-42dc-9a74-a417e44cb87e","campaign_ids":["bcda01f7-21c9-4e12-9849-0a375b548467"],"connected_sender_eaccounts":["hamzah@gethmzautomation.com","hamzah@gethmzautomations.com","hamzah@hmzautomation.com","hamzah@hmzautomations.com","hamzah@hubhmzautomation.com","hamzah@hubhmzautomations.com","hamzah@labshmzautomation.com","hamzah@labshmzautomations.com","hamzah@onehmzautomation.com","hamzah@onehmzautomations.com","hamzah@teamhmzautomation.org","hamzah@teamhmzautomations.com","zahid@gethmzautomation.com","zahid@gethmzautomations.com","zahid@hmzautomation.com","zahid@hmzautomations.com","zahid@hubhmzautomation.com","zahid@hubhmzautomations.com","zahid@labshmzautomation.com","zahid@labshmzautomations.com","zahid@onehmzautomation.com","zahid@onehmzautomations.com","zahid@teamhmzautomation.org","zahid@teamhmzautomations.com"]};
// HMZ_INJECT_END:ALLOWLISTS
// HMZ_INJECT_END:ALLOWLISTS
// HMZ_INJECT_END:ALLOWLISTS
// HMZ_INJECT_END:ALLOWLISTS

return items.map((item) => {
  const input = item.json || {};
  const nes = input.nes || {};
  const prefilter = input.prefilter || {};
  const entrySource = input.entry_source || 'UNKNOWN';

  if (entrySource !== 'PRODUCTION_WEBHOOK') {
    return {
      json: {
        ...input,
        security_gate: { checked: false, entry_source: entrySource, passed: true, reasons: [] },
      },
    };
  }

  const reasons = [];
  const workspaceId = nes.workspace_id || null;
  const campaignId = nes.campaign_id || (nes.campaign_context && nes.campaign_context.campaign_id) || null;
  const eaccount = nes.eaccount || null;

  const workspaceAllowed = !!ALLOWLISTS.workspace_id && workspaceId === ALLOWLISTS.workspace_id;
  if (!workspaceAllowed) reasons.push('WORKSPACE_NOT_ALLOWLISTED');

  // A missing/blank workspace_id can never allowlist a campaign or sender:
  // both checks are gated on workspaceAllowed.
  const campaignAllowed = workspaceAllowed && ALLOWLISTS.campaign_ids.length > 0 && !!campaignId && ALLOWLISTS.campaign_ids.includes(campaignId);
  if (!campaignAllowed) reasons.push('CAMPAIGN_NOT_ALLOWLISTED_OR_WORKSPACE_NOT_ALLOWLISTED');

  const senderAllowed = workspaceAllowed && ALLOWLISTS.connected_sender_eaccounts.length > 0 && !!eaccount && ALLOWLISTS.connected_sender_eaccounts.includes(eaccount);
  if (!senderAllowed) reasons.push('SENDER_EACCOUNT_NOT_ALLOWLISTED_OR_WORKSPACE_NOT_ALLOWLISTED');

  if (prefilter.is_self_sent) reasons.push('SELF_SENT');
  if (prefilter.is_unsupported_event_type) reasons.push('UNSUPPORTED_EVENT_TYPE');
  if (prefilter.is_malformed_payload) reasons.push('MALFORMED_PAYLOAD');
  if (prefilter.is_duplicate_event) reasons.push('DUPLICATE_EVENT');

  const passed = workspaceAllowed && campaignAllowed && senderAllowed &&
    !prefilter.is_self_sent && !prefilter.is_unsupported_event_type &&
    !prefilter.is_malformed_payload && !prefilter.is_duplicate_event;

  return {
    json: {
      ...input,
      security_gate: {
        checked: true,
        entry_source: entrySource,
        workspace_allowed: workspaceAllowed,
        campaign_allowed: campaignAllowed,
        sender_allowed: senderAllowed,
        passed,
        reasons,
      },
    },
  };
});

const items = $input.all();

return items.map((item) => {
  const input = item.json || {};
  return {
    json: {
      ...input,
      terminal: {
        schema_version: '1.0',
        result: 'REJECTED',
        reason: 'PRODUCTION_SECURITY_GATE_FAILED',
        security_gate: input.security_gate || null,
      },
    },
  };
});
